-- Create strains table
CREATE TABLE IF NOT EXISTS public.strains (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL UNIQUE,
  type TEXT NOT NULL CHECK (type IN ('indica', 'sativa', 'hybrid', 'auto')),
  thc_range TEXT,
  cbd_range TEXT,
  flowering_days_min INTEGER,
  flowering_days_max INTEGER,
  difficulty TEXT CHECK (difficulty IN ('easy', 'medium', 'hard')),
  yield_indoor TEXT,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Enable RLS
ALTER TABLE public.strains ENABLE ROW LEVEL SECURITY;

-- Everyone can read strains
CREATE POLICY "Anyone can read strains" ON public.strains FOR SELECT USING (true);

-- Only service role can insert/update
CREATE POLICY "Service role can manage strains" ON public.strains FOR ALL USING (auth.role() = 'service_role');

-- Index for search
CREATE INDEX IF NOT EXISTS idx_strains_name ON public.strains (lower(name));
CREATE INDEX IF NOT EXISTS idx_strains_type ON public.strains (type);

-- Seed data
ON CONFLICT (name) DO NOTHING;
