INSERT INTO public.strains (name, type, thc_range, cbd_range, flowering_days_min, flowering_days_max, difficulty, yield_indoor, description) VALUES
('OG Kush', 'hybrid', '20-26%', '0.1-0.3%', 56, 65, 'medium', '400-500 g/m²', 'Leyenda californiana con aroma terroso y cítrico. Produce efectos potentes y relajantes, considerada la madre de muchas cepas modernas.'),
